mapper.update:
UPDATE sys_system_config
config_key = #{config_key}, config_value = #{config_value}, remark = #{remark}, update_time = DATE_FORMAT(NOW(), '%Y-%m-%d %H:%i:%s'),
WHERE id = #{id}

mapper.select:
SELECT  FROM sys_system_config su WHERE 1 = 1
AND su.id = #{id}
AND su.config_key = #{config_key}
AND su.config_value LIKE CONCAT('%',#{config_value},'%')
ORDER BY su.id DESC

SELECT  FROM sys_system_config su WHERE 1 = 1
AND su.id = #{pd.id}
AND su.config_key = #{pd.config_key}
AND su.config_value LIKE CONCAT('%',#{pd.config_value},'%')
ORDER BY su.id DESC
